  { employee_id: 'EMP-ZA-003', full_name: 'Sipho Nkosi', country: 'ZA', grossMonthlySalary: 18000, age: 38, medicalAid: true, medicalDependents: 3, retirementFundPct: 0 },
  { employee_id: 'EMP-GB-001', full_name: 'James Whitfield', country: 'GB', grossMonthlySalary: 5000, studentLoanPlan: 'plan2', pensionPct: 5 },
  { employee_id: 'EMP-GB-002', full_name: 'Priya Sharma', country: 'GB', grossMonthlySalary: 3200, pensionPct: 5 },
  { employee_id: 'EMP-GB-003', full_name: 'Oliver Chen', country: 'GB', grossMonthlySalary: 8500, studentLoanPlan: 'plan1', pensionPct: 8 },
