return employees.map(e => ({ json: e }));

const items = $input.all();
const results = [];

const brackets = [
  { min: 0, max: 237100, rate: 0.18, base: 0 },
  { min: 237101, max: 370500, rate: 0.26, base: 42678 },
  { min: 370501, max: 512800, rate: 0.31, base: 77362 },
  { min: 512801, max: 673000, rate: 0.36, base: 121475 },
  { min: 673001, max: 857900, rate: 0.39, base: 179147 },
  { min: 857901, max: 1817000, rate: 0.41, base: 251258 },
  { min: 1817001, max: Infinity, rate: 0.45, base: 644489 },
];

for (const item of items) {
  const emp = item.json;
  const gross = emp.grossMonthlySalary;
  const retPct = emp.retirementFundPct || 0;
  const retMonthly = gross * (retPct / 100);
  const annualGross = gross * 12;
  const retDeductible = Math.min(retMonthly * 12, annualGross * 0.275, 350000);
  const taxable = annualGross - retDeductible;

  let annualPAYE = 0;
  for (const b of brackets) {
    if (taxable <= b.max) { annualPAYE = b.base + (taxable - b.min) * b.rate; break; }
  }
  annualPAYE -= 17235;

  let medCredit = 0;
  if (emp.medicalAid) {
    medCredit = 364 + (emp.medicalDependents >= 1 ? 364 : 0) + Math.max(0, (emp.medicalDependents || 0) - 1) * 246;
    annualPAYE -= medCredit * 12;
  }
  annualPAYE = Math.max(0, annualPAYE);

  const monthlyPAYE = Math.round(annualPAYE / 12 * 100) / 100;
  const uif = Math.round(Math.min(gross, 17712) * 0.01 * 100) / 100;
  const retFund = Math.round(retMonthly * 100) / 100;
  const totalDed = monthlyPAYE + uif + retFund;

  results.push({ json: {
    employee_id: emp.employee_id, full_name: emp.full_name,
    country: 'ZA', currency: 'ZAR', grossSalary: gross,
    totalDeductions: Math.round(totalDed * 100) / 100,
    netSalary: Math.round((gross - totalDed) * 100) / 100,
  }});
}
return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const emp = item.json;
  const gross = emp.grossMonthlySalary;
  const annual = gross * 12;

  let pa = 12570;
  if (annual > 100000) pa = Math.max(0, 12570 - Math.floor((annual - 100000) / 2));
  const taxable = Math.max(0, annual - pa);

  let tax = 0, rem = taxable;
  tax += Math.min(rem, 37700) * 0.20; rem = Math.max(0, rem - 37700);
  tax += Math.min(rem, 74870) * 0.40; rem = Math.max(0, rem - 74870);
  if (rem > 0) tax += rem * 0.45;
  const monthlyTax = Math.round(tax / 12 * 100) / 100;

  let ni = 0;
  if (annual > 12570) {
    ni += Math.min(annual - 12570, 50270 - 12570) * 0.08;
    if (annual > 50270) ni += (annual - 50270) * 0.02;
  }
  const monthlyNI = Math.round(ni / 12 * 100) / 100;

  const plans = { plan1: 24990, plan2: 27295, plan4: 31395, plan5: 25000, postgrad: 21000 };
  const slRate = emp.studentLoanPlan === 'postgrad' ? 0.06 : 0.09;
  const slThreshold = plans[emp.studentLoanPlan] || 0;
  const monthlySL = emp.studentLoanPlan && annual > slThreshold ? Math.round((annual - slThreshold) * slRate / 12 * 100) / 100 : 0;

  const pensionRate = emp.pensionPct ? emp.pensionPct / 100 : 0.05;
  const qualEarnings = Math.max(0, Math.min(annual, 50270) - 6240);
  const monthlyPension = Math.round(qualEarnings * pensionRate / 12 * 100) / 100;

  const totalDed = monthlyTax + monthlyNI + monthlySL + monthlyPension;

  results.push({ json: {
    employee_id: emp.employee_id, full_name: emp.full_name,
    country: 'GB', currency: 'GBP', grossSalary: gross,
    totalDeductions: Math.round(totalDed * 100) / 100,
    netSalary: Math.round((gross - totalDed) * 100) / 100,
  }});
}
return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const emp = item.json;
  const gross = emp.grossMonthlySalary;
  const annual = gross * 12;
  const filing = emp.filingStatus || 'single';

  const k401Pct = emp.fourOhOnekPct || 0;
  const k401Annual = Math.min(annual * (k401Pct / 100), 23500);
  const preTax = k401Annual;

  const stdDed = filing === 'married_jointly' ? 30000 : 15000;
  const fedTaxable = Math.max(0, annual - preTax - stdDed);
  const brackets = filing === 'married_jointly'
    ? [{m:0,x:23850,r:0.10,b:0},{m:23851,x:96950,r:0.12,b:2385},{m:96951,x:206700,r:0.22,b:11157},{m:206701,x:394600,r:0.24,b:35303}]
    : [{m:0,x:11925,r:0.10,b:0},{m:11926,x:48475,r:0.12,b:1192.5},{m:48476,x:103350,r:0.22,b:5578.5},{m:103351,x:197300,r:0.24,b:17651.5}];

  let fedTax = 0;
  for (const b of brackets) {
    if (fedTaxable <= b.x) {
      fedTax = b.m === 0 ? fedTaxable * b.r : b.b + (fedTaxable - b.m + 1) * b.r;
      break;
    }
  }
  const monthlyFed = Math.round(fedTax / 12 * 100) / 100;
  const monthlySS = Math.round(Math.min(annual - preTax, 176100) * 0.062 / 12 * 100) / 100;
  let medTax = (annual - preTax) * 0.0145;
  if (annual - preTax > 200000) medTax += (annual - preTax - 200000) * 0.009;
  const monthlyMed = Math.round(medTax / 12 * 100) / 100;

  const states = {
    TX: { brackets: [], sd: 0 },
    CA: { sd: 5540, brackets: [{m:0,x:10412,r:0.01},{m:10413,x:24684,r:0.02},{m:24685,x:38959,r:0.04},{m:38960,x:54081,r:0.06},{m:54082,x:68350,r:0.08},{m:68351,x:349137,r:0.093}] },
    NY: { sd: 8000, brackets: [{m:0,x:8500,r:0.04},{m:8501,x:11700,r:0.045},{m:11701,x:13900,r:0.0525},{m:13901,x:80650,r:0.0585},{m:80651,x:215400,r:0.0625}] }
  };
  const sc = states[emp.state] || states.TX;
  let stateTax = 0;
  if (sc.brackets.length > 0) {
    const stTaxable = Math.max(0, annual - preTax - sc.sd);
    let prev = 0;
    for (const b of sc.brackets) {
      if (stTaxable <= b.x) { stateTax += (stTaxable - prev) * b.r; break; }
      else { stateTax += (b.x - prev) * b.r; prev = b.x; }
    }
  }
  const monthlyState = Math.round(stateTax / 12 * 100) / 100;
  const monthly401k = Math.round(k401Annual / 12 * 100) / 100;

  const totalDed = monthlyFed + monthlySS + monthlyMed + monthlyState + monthly401k;

  results.push({ json: {
    employee_id: emp.employee_id, full_name: emp.full_name,
    country: 'US', currency: 'USD', grossSalary: gross,
    totalDeductions: Math.round(totalDed * 100) / 100,
    netSalary: Math.round((gross - totalDed) * 100) / 100,
  }});
}
return results;

const payslips = $input.all().map(i => i.json);
const payPeriod = new Date().toISOString().slice(0, 7);

const countries = {};
for (const p of payslips) {
  if (!countries[p.country]) {
    countries[p.country] = { country: p.country, currency: p.currency, employees: 0, totalGross: 0, totalDeductions: 0, totalNet: 0, payslips: [] };
  }
  const c = countries[p.country];
  c.employees++;
  c.totalGross += p.grossSalary;
  c.totalDeductions += p.totalDeductions;
  c.totalNet += p.netSalary;
  c.payslips.push({ employee_id: p.employee_id, full_name: p.full_name, gross: p.grossSalary, deductions: p.totalDeductions, net: p.netSalary });
}

for (const key of Object.keys(countries)) {
  const c = countries[key];
  c.totalGross = Math.round(c.totalGross * 100) / 100;
  c.totalDeductions = Math.round(c.totalDeductions * 100) / 100;
  c.totalNet = Math.round(c.totalNet * 100) / 100;
}

const totalEmployees = payslips.length;

return [{ json: {
  reportTitle: 'Monthly Payroll Report - ' + payPeriod,
  payPeriod,
  generatedAt: new Date().toISOString(),
  totalEmployees,
  byCountry: countries,
  summary: {
    countriesProcessed: Object.keys(countries).length,
    totalEmployees,
  }
}}];
